import { Component } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
@Component({
  selector: 'app-signup',
  standalone: true,
  imports: [CommonModule,FormsModule],
  templateUrl: './signup.component.html',
  styleUrls: ['./signup.component.scss']
})
export class SignupComponent {
activeRole: 'patient' | 'doctor' | 'admin' = 'patient';

  // تجميع بيانات الفورم في كائن واحد
  registerData = {
    firstName: '',
    lastName: '',
    email: '',
    mobileNumber: '',
    nic: '',
    dob: '',
    address: '',
    gender: '',
    password: '',
    confirmPassword: ''
  };

  // دالة التبديل بين الأدوار الثلاثة
  selectRole(role: 'patient' | 'doctor' | 'admin') {
    this.activeRole = role;
  }

  onSubmit() {
    // التأكد من تطابق كلمة المرور كمثال للـ Validation
    if (this.registerData.password !== this.registerData.confirmPassword) {
      alert('كلمة المرور غير متطابقة!');
      return;
    }

    console.log('بيانات التسجيل الحالية لـ ' + this.activeRole + ' هي:', this.registerData);
    // هنا هتقدري تربطي مع الـ Service عشان تبعتي البيانات للـ Backend (Flask) بعدين
  }
}
}
